section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/qa-rollback-trigger-canon.json",
  "type": "object",
  "title": "QA Rollback Trigger Canon",
  "required": [
    "canon_id",
    "triggers",
    "action_enum_used",
    "last_reviewed"
  ],
  "additionalProperties": false,
  "properties": {
    "canon_id": {
      "type": "string",
      "minLength": 1,
      "description": "Canon identifier."
    },
    "triggers": {
      "type": "array",
      "items": {
        "type": "object"
      },
      "description": "List of {id, signal, threshold, window_minutes, owner, action}."
    },
    "action_enum_used": {
      "type": "array",
      "items": {
        "type": "string"
      },
      "description": "Subset of [auto_rollback, one_click_rollback]."
    },
    "last_reviewed": {
      "type": "string",
      "minLength": 1,
      "description": "ISO date."
    },
    "firings": {
      "type": "array",
      "items": {
        "type": "object"
      },
      "description": "Recorded firings: {id, ts, rolled_back, reason, owner}."
    }
  }
}
